import React, { useEffect, useState, useRef } from 'react';
import {
  View,
  Text,
  ActivityIndicator,
  FlatList,
  TouchableOpacity,
  Alert,
  StyleSheet,
  PermissionsAndroid,
  Platform,
  Image,
} from 'react-native';

import ViewShot from 'react-native-view-shot';


import ReactNativePosPrinter, {
  ThermalPrinterDevice,
} from 'react-native-thermal-pos-printer';

import {
  fetchTicketInfraction,
  buildEscPosTicket,
  fillTemplate,
  stringToBytes,
} from '@/services/ticket';



interface PrinterItem {
  device: ThermalPrinterDevice;
}


/* =========================
   COMPONENTE PRINCIPAL
========================= */
export default function App() {

  const [printers, setPrinters] = useState<PrinterItem[]>([]);
  const [selectedPrinter, setSelectedPrinter] = useState<PrinterItem | null>(null);
  const [loading, setLoading] = useState(false);
  const viewShotRef = useRef<ViewShot>(null);


 // Escala para mejorar la resolución de la imagen capturada

const IMG1 = "data:image/png;base64,";
const IMG2 = "data:image/png;base64,";
const IMG3 = "data:image/png;base64,";
const IMG4 = "data:image/png;base64,";

  /* =========================
     PERMISOS BLUETOOTH
  ========================= */
  const requestPermissions = async () => {
    if (Platform.OS === 'android') {
      await PermissionsAndroid.requestMultiple([
        PermissionsAndroid.PERMISSIONS.BLUETOOTH_CONNECT,
        PermissionsAndroid.PERMISSIONS.BLUETOOTH_SCAN,
        PermissionsAndroid.PERMISSIONS.ACCESS_FINE_LOCATION,
      ]);
    }
  };

  /* =========================
     INICIALIZAR IMPRESORAS
  ========================= */
  useEffect(() => {
    (async () => {
      setLoading(true);

      try {
        await requestPermissions();

        await ReactNativePosPrinter.init({
          encoding: 'UTF-8',
          width: 576,
        });

        const devices = await ReactNativePosPrinter.getDeviceList();

        const printerItems: PrinterItem[] =
          devices?.map((device) => ({ device })) || [];

        setPrinters(printerItems);
      } catch (e) {
        console.error('Error inicializando impresoras:', e);
        setPrinters([]);
        Alert.alert('Error', 'No se pudieron cargar las impresoras');
      }

      setLoading(false);
    })();
  }, []);

  /* =========================
     SELECCIONAR IMPRESORA
  ========================= */

  const handleSelectPrinter = (printer: PrinterItem) => {
    setSelectedPrinter(printer);
  };

    /* =========================
     CAPTURAR IMAGENES
  ========================= */

  const captureImages = async () => {

   
   const base64 = await viewShotRef.current?.capture?.();

  if (!base64) {
    console.log("No se pudo capturar la imagen");
    return;
  }
    
    const finalImage = `data:image/png;base64,${base64}`;

    await ReactNativePosPrinter.printImage(finalImage,  {
      align: "CENTER",
      width: 576,
    });

  };
    


  /* =========================
     IMPRIMIR TICKET
  ========================= */
  const print = async () => {

    if (!selectedPrinter) {
      Alert.alert('Error', 'Selecciona una impresora primero');
      return;
    }

    try {

      //await ReactNativePosPrinter.disconnectPrinter().catch(() => {});
      setLoading(true);

      // Obtener datos del endpoint y templates
         const response = await fetchTicketInfraction();

    if (!response.success) {
      Alert.alert('Error', response.message);
      return;
    }

    let template = response.data;

    // ==========================
    //  Datos dinámicos
    // ==========================
    const data = {
      placa: 'ABC123',
      entidadF: 'Puebla',
      marcaVehicle: 'Nissan',
      lineaVehicle: 'Versa',
      tipoVehicle: 'Sedan',
      modeloVehicle: '2022',
      velocidadMax: 80,
      velocidadVehicle: 110,
      agente: 'oficial 1',
      folio: 'F12345',
      nameInfractor: 'David Flores',
      custodia: 'la autoridad competente adscrita a la Secretaría de Movilidad y Transporte del Estado de Puebla'
    };


    // ==========================
    //  Reemplazo @@variables 
    // ==========================
    const filled = fillTemplate(template, data);


      // Conectar impresora
      await ReactNativePosPrinter.connectPrinter(
        selectedPrinter.device.getAddress(),
        { encoding: 'UTF-8' }
      );


      //console.log("RAW API TEXT:", response.data);
      //await ReactNativePosPrinter.printText('\n');

      // imprimir las 4 imagenes
      await captureImages();

      /*
      //Construir ticket ESC/POS
      const escposString = buildEscPosTicket(response.data);
       const escposString = buildEscPosTicket(filled);
      */

    // --------------------------
    // Fragmentación automática por capítulos
    // --------------------------
    const sections = filled.split('\n\n\n'); // separar por capítulos (doble salto de línea)

    for (const section of sections) {
      // Construir ticket ESC/POS para la sección
      const escposString = buildEscPosTicket(section);

      // Convertir a bytes
     const escposBytes = Array.from(escposString).map((c) => c.charCodeAt(0));
      
      // Imprimir
      await ReactNativePosPrinter.printRaw(escposBytes);

    // Espera para que la impresora procese el fragmento
      await new Promise(res => setTimeout(res, 150));
    }

       // QR Code with high error correction
    await ReactNativePosPrinter.printQRCode('https://fotoinfraccionf.puebla.gob.mx/login?from=%2F', {
      align: 'CENTER',
      size: 4,
      errorLevel: 'H'
    });


      // Desconectar
      await ReactNativePosPrinter.disconnectPrinter();

      Alert.alert('Éxito', 'Ticket impreso correctamente');
    } catch (err: any) {
      console.log('Print Error:', err);

      Alert.alert(
        'Error al imprimir',
        err?.message || 'Error desconocido'
      );
  
    } finally {
      setLoading(false);
    }
    
  };

  return (
    
    <View style={styles.container}>

      <View style={styles.header}>
        <Text style={styles.title}>Impresoras disponibles</Text>
      </View>
      
      <View style={styles.content}>
        {loading ? (
          <View style={styles.loadingContainer}>
            <ActivityIndicator size="large" color="#2563EB" />
            <Text style={styles.loadingText}>Cargando...</Text>
          </View>
        ) : (
          <FlatList
            data={printers}
            keyExtractor={(item) =>
              item.device.getAddress() + (item.device.getName() || '')
            }
            renderItem={({ item }) => (
              <TouchableOpacity
                style={[
                  styles.printerItem,
                  selectedPrinter?.device.getAddress() ===
                    item.device.getAddress() && styles.selectedPrinter,
                ]}
                onPress={() => handleSelectPrinter(item)}
                activeOpacity={0.8}
              >
                <View style={styles.printerInfo}>
                  <Text style={styles.printerName}>
                    {item.device.getName() ||
                      item.device.getAddress() ||
                      'Impresora desconocida'}
                  </Text>

                  <Text style={styles.printerAddress}>
                    {item.device.getAddress()}
                  </Text>

                  <Text style={styles.printerType}>
                    {item.device.getType()}
                  </Text>
                </View>

                {selectedPrinter?.device.getAddress() ===
                  item.device.getAddress() && (
                  <Text style={styles.selectedIndicator}>✓</Text>
                )}
              </TouchableOpacity>
            )}
          />
        )}
         {/* IMAGENES PARA CAPTURAR */}
         { /*  */}
         { /**/}

{/*<View style={{ position: 'absolute', left: -1000, top: -1000 }}>*/}
      <ViewShot
        ref={viewShotRef}
        options={{ format: "png", result: "base64", quality: 1,  }}
      >

        <View style={{ width: 576, backgroundColor: "white",  }}>

          <View style={{ flexDirection: "row", }}>
            <Image source={{ uri: IMG1 }} style={{ width: 200, height: 100, resizeMode: "contain" }} />
            <Image source={{ uri: IMG2 }} style={{ width: 200, height: 100, resizeMode: "contain" }} />
         
          </View>

          <View style={{ flexDirection: "row", width: 576, }}>
            <Image source={{ uri: IMG3 }} style={{ width: 200, height: 100, resizeMode: "contain" }} />
            <Image source={{ uri: IMG4 }} style={{ width: 200, height: 100, resizeMode: "contain" }} />
           
          </View>

        </View>

      </ViewShot>

{/*</View>*/}


      
        <TouchableOpacity
          onPress={print}
          style={[
            styles.printButton,
            {
              backgroundColor: selectedPrinter ? '#2563EB' : '#D1D5DB',
            },
          ]}
          disabled={!selectedPrinter}
        >
          <Text style={styles.printButtonText}>IMPRIMIR TICKET</Text>
        </TouchableOpacity>
      </View>
    </View>
    
  );
}


const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F9FAFB',
  },

  header: {
    padding: 16,
    borderBottomWidth: 1,
    borderBottomColor: '#E5E7EB',
  },

  title: {
    fontSize: 18,
    fontWeight: 'bold',
    color: '#1F2937',
  },

  content: {
    flex: 1,
    padding: 16,
  },

  loadingContainer: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },

  loadingText: {
    marginTop: 16,
    color: '#2563EB',
    fontSize: 16,
    fontWeight: '600',
  },

  printerItem: {
    backgroundColor: 'white',
    borderRadius: 12,
    borderWidth: 2,
    borderColor: '#E5E7EB',
    padding: 16,
    marginBottom: 8,
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },

  selectedPrinter: {
    borderColor: '#2563EB',
  },

  printerInfo: {
    flex: 1,
  },

  printerName: {
    fontSize: 16,
    fontWeight: 'bold',
    color: '#1F2937',
  },

  printerAddress: {
    fontSize: 12,
    color: '#6B7280',
  },

  printerType: {
    fontSize: 12,
    color: '#6B7280',
    fontStyle: 'italic',
  },

  selectedIndicator: {
    fontSize: 22,
    color: '#2563EB',
    fontWeight: 'bold',
  },

  printButton: {
    borderRadius: 12,
    padding: 16,
    alignItems: 'center',
    marginTop: 16,
  },

  printButtonText: {
    color: 'white',
    fontSize: 16,
    fontWeight: 'bold',
  },
});